INSERT INTO public.photos VALUES (25492, 'Plaza del Carmen 1963', 'Vista aâ”śÂ®rea capturada sobrevolando la plaza del Carmen y centrando el objetivo donde estuviera el antiguo y homâ”śâ”‚nimo cuartel del ejâ”śÂ®rcito, que ya derribado, su solar era utilizado provisionalmente para acoger espectâ”śĂ­culos circenses por ejemplo durante las Fiestas del Pilar, como es el caso. El festivo perâ”śÂˇmetro ocupado por el Circo Monumental, estâ”śĂ­ delimitado entre las calles de la Vieja Guardia (actual de Marcelino de Isâ”śĂ­bal), Capitâ”śĂ­n Portolâ”śÂ®s (actual del Doctor Val-Carreres), y General Sanjurjo (actual tramo de la avenida de Câ”śÂ®sar Augusto). Hacia la izquierda, la imponente presencia del Frontâ”śâ”‚n Aragonâ”śÂ®s, recayente a la calle de Josâ”śÂ® Luis Albareda. Al fondo, el punto de confluencia entre el paseo de Pamplona, la calle de Hernâ”śĂ­n Cortâ”śÂ®s y el arranque del paseo de Marâ”śÂˇa Agustâ”śÂˇn.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65076500, -0.88521400, '0101000020E610000054C37E4FAC53ECBFD3307C444CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50833723873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50833723873.webp', 'https://www.flickr.com/photos/zaragozaantigua/50833723873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26016, 'Vista c.1944', 'Desde la altura del Edificio Elâ”śÂˇseos, vista orientada hacia la plaza de Aragâ”śâ”‚n y el paseo de la Independencia. La plaza sigue siendo un espacio definido por la continuidad del bulevar y la escala urbanâ”śÂˇstica de los hotelitos que la rodean, si bien en la imagen destacan las obras de remodelaciâ”śâ”‚n de dos de sus inmuebles. A la derecha y con andamios de obra, la ampliaciâ”śâ”‚n en altura y volumen hasta el paseo de Marina Moreno del nâ”¬â•‘ 4, con proyecto del arquitecto Fausto Garcâ”śÂˇa Marco. Confrontando y al otro lado de la plaza, el antiguo nâ”¬â•‘ 12 proyectado por Antonio Miranda en 1888, para el que Miguel â”śĂĽngel Navarro Pâ”śÂ®rez y Josâ”śÂ® Luis Navarro Anguela habâ”śÂˇan ideado una radical ampliaciâ”śâ”‚n y reforma que comenzarâ”śÂˇa poco despuâ”śÂ®s. Ademâ”śĂ­s, destaca la cobertura en caâ”śâ–’izo que seâ”śâ–’ala la reforma del veterano inmueble del nâ”¬â•‘ 37 del paseo de la Independencia, esquinero con la calle de Juan Bruil.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22556709864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22556709864.webp', 'https://www.flickr.com/photos/zaragozaantigua/22556709864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26043, 'Plaza de Aragâ”śâ”‚n 1963', 'Imagen capturada desde cierta altura, lo que permite una buena visual de las plazas de Paraâ”śÂˇso, Aragâ”śâ”‚n, y el paseo de la Independencia, tras su conversiâ”śâ”‚n en vâ”śÂˇas de alta capacidad para trâ”śĂ­fico rodado por el interior de la ciudad. Al fondo, insâ”śâ”‚lita visiâ”śâ”‚n de las chimeneas de la antigua azucarera del Arrabal, sobresaliendo por encima de la antigua fachada de edificios del Coso. Una unidad 200, hacia el paseo de Calvo Sotelo, y otra de la lâ”śÂˇnea "Torrero-Delicias", hacia el paseo del General Mola. Fuente visual: www.delcampe.es', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31417914755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31417914755.webp', 'https://www.flickr.com/photos/zaragozaantigua/31417914755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26071, 'Plaza de Aragâ”śâ”‚n, 1963', 'Vista aâ”śÂ®rea capturada sobrevolando el entorno de la plaza de Aragâ”śâ”‚n, definida por el contraste entre la nueva autopista que conectaba la plaza de Espaâ”śâ–’a y la de Basilio Paraâ”śÂˇso, y la presencia de los venerables hotelitos que, aun bastante modificados, perduraban en ambos lados de la plaza desde su establecimiento a finales del siglo XIX. Este contraste empezâ”śâ”‚ a desaparecer cuando los hotelitos fueron sustituidos por los actuales edificios comerciales y residenciales que los sustituyeron en los aâ”śâ–’os y dâ”śÂ®cadas siguientes. Hacia el fondo destaca la gran estructura del Frontâ”śâ”‚n Aragonâ”śÂ®s, y la câ”śâ•‘pula de la iglesia de Santiago el Mayor y la torre de San Pablo hacia la derecha. El desarrollismo estaba a punto de modificar radicalmente lo que aparece en esta vista, con el surgimiento de algunos de los locales rascacielos de la ciudad.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64844800, -0.88493500, '0101000020E61000008CBE82346351ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50836749018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50836749018.webp', 'https://www.flickr.com/photos/zaragozaantigua/50836749018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26073, 'Plaza de Aragâ”śâ”‚n, 1925', 'Bien interesante vista aâ”śÂ®rea centrada en la plaza de Aragâ”śâ”‚n y el paseo de la Independencia, que arranca en la parte superior de la plaza de la Constituciâ”śâ”‚n. A la derecha, el entorno de la antigua Huerta de Santa Engracia, todavâ”śÂˇa ocupado en parte por el Saturno Park.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64854400, -0.88480700, '0101000020E61000002DB308C55650ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51099057799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51099057799.webp', 'https://www.flickr.com/photos/zaragozaantigua/51099057799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20946, 'Puerta del Carmen 1808', 'Juramento de los defensores de Zaragoza en la plazuela del Carmen, Nicolâ”śĂ­s Ruiz de Valdivia, â”śâ”‚leo sobre lienzo, 1866. Depositado en las Cortes de Aragâ”śâ”‚n. "La Junta de Salvaciâ”śâ”‚n nombrada el 24 de junio de 1808 en Zaragoza, arengando a los defensores del reducto de la Puerta del Carmen. El Marquâ”śÂ®s de Lazâ”śĂ­n, hermano de Palafox, toma juramento a los defensores de Zaragoza ante una bandera blanca con una enseâ”śâ–’a central representando la Virgen del Pilar. La representaciâ”śâ”‚n es interesante por reflejar monumentos desaparecidos en los Sitios: la torre del Pino, la antigua câ”śâ•‘pula de la iglesia de san Ildefonso, y el remate (el leâ”śâ”‚n rampante del escudo de Zaragoza) de la puerta del Carmen (en la actualidad, desaparecido). A la derecha se reconoce a Mariano Cerezo, con sable y chistera, inspirado en el grabado de Gâ”śĂ­lvez y Brambila." Fuente: agustinazaragoza.wordpress.com/2014/06/24/24-de-junio-de-...', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64961200, -0.88779200, '0101000020E610000057D0B4C4CA68ECBF698B6B7C26D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012554499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012554499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012554499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20966, 'Puerta del Carmen 1815', 'Pintura de â”śĂĽngel Dâ”śÂˇaz Domâ”śÂˇnguez, realizada en 1927, con una recreaciâ”śâ”‚n eclâ”śÂ®ctica, castiza y regionalista, de una procesionaria de majos y majas que, desde el Paseo de las Tapias, entran a Zaragoza por una puerta del Carmen ya daâ”śâ–’ada por los sucesos bâ”śÂ®licos de 1808-1809. Al fondo, los otros edificios representativos de la zona (Convento de la Encarnaciâ”śâ”‚n, iglesia de San Ildefonso) aparecen dispuestos muy libremente. Si las figuras pretenden ser muy goyescas, pero del Goya de antes de 1808, la pincelada y los colores son mâ”śĂ­s de Zuloaga. Fuente visual: "Artistas aragoneses desde Goya a nuestros dâ”śÂˇas", Ayto. Zaragoza, 1991.', 1815, 1815, 1815, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18901770383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18901770383.webp', 'https://www.flickr.com/photos/zaragozaantigua/18901770383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21006, 'Puerta del Carmen c.1860', '"Puerta del Carmen en Zaragoza". La Puerta parece una puerta, e indica el ancho de la calle a la que da acceso. Al fondo, a la izquierda, la câ”śâ•‘pula de la Iglesia del antiguo convento dominico de San Ildefonso (antes de ser destruida por un rayo) y, mâ”śĂ­s cercana, la câ”śâ•‘pula de media naranja del convento de la Encarnaciâ”śâ”‚n. Por el vano central de la puerta, entre â”śĂ­rboles, surge la Torre Nueva, y su triple chapela barroca. Fuente visual: Autor anâ”śâ”‚nimo, Colecciâ”śâ”‚n Madrazo, proveniente de la familia Daza Campos (Adquirida por el Museo del Prado)', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64982700, -0.88754200, '0101000020E61000002272FA7ABE66ECBF6687F8872DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14911532362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14911532362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14911532362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21016, 'Puerta del Carmen 1867', '"Puerta de Nuestra Seâ”śâ–’ora del Câ”śĂ­rmen, en Zaragoza", xilografâ”śÂˇa de Tomâ”śĂ­s Carlos Capuz incluida en la Crâ”śâ”‚nica general de Espaâ”śâ–’a, Madrid, 1867.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19346051710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19346051710.webp', 'https://www.flickr.com/photos/zaragozaantigua/19346051710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21187, 'Puerta del Carmen c.1898', 'Puerta del Carmen, vista desde el paseo de la Lealtad. El almacâ”śÂ®n de sal de la derecha darâ”śĂ­ paso aâ”śâ–’os despuâ”śÂ®s al Cafâ”śÂ® Levante (fundado en 1895 y situado allâ”śÂˇ en 1903, aproximadamente). Fuente visual: Foto Alday, en www.kutxateka.eus/', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.64983200, -0.88772500, '0101000020E610000063EE5A423E68ECBF78F2E9B12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37931235106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37931235106.webp', 'https://www.flickr.com/photos/zaragozaantigua/37931235106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21217, 'Convento de la Encarnaciâ”śâ”‚n 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 32, Zaragoza 1908 - Centenario de los Sitios", 1907. "De edificaciâ”śâ”‚n reciente; construido en el solar del antiguo convento de la Encarnaciâ”śâ”‚n que destruyeron los franceses. Su proximidad a la puerta del Carmen, le hizo punto muy estratâ”śÂ®gico para la defensa, como tambiâ”śÂ®n lo fueron el convento y el colegio del Carmen inmediatos, donde hoy se encuentran la Escuela de Veterinaria y el Cuartel de Artillerâ”śÂˇa." Convento de la Encarnaciâ”śâ”‚n de las Madres Carmelitas, en el actual chaflâ”śĂ­n de Câ”śÂ®sar Augusto con el paseo Marâ”śÂˇa Agustâ”śÂˇn. Sustituido por otro en la misma ubicaciâ”śâ”‚n. Vista trasera. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65019300, -0.88779100, '0101000020E610000040DCD5ABC868ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15572137949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15572137949.webp', 'https://www.flickr.com/photos/zaragozaantigua/15572137949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21255, 'Puerta del Carmen 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 21, Zaragoza 1908 - Centenario de los Sitios", 1907. "De donde fueron siempre rechazados los franceses en sus porfiados ataques. En uno de ellos fue muerto el valiente patriota Romeo, capitâ”śĂ­n retirado y natural de Tudela. En torno a esta puerta, verdadero monumento nacional, se proyecta hoy la formaciâ”śâ”‚n de una gran plaza." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582349650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582349650.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582349650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21257, 'Cuartel de Hernâ”śĂ­n Cortâ”śÂ®s 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 23, Zaragoza 1908 - Centenario de los Sitios", 1907. "Situado en el camino viejo de Casa-Blanca, por donde los franceses habâ”śÂˇan de acercarse a Zaragoza, el pueblo llevâ”śâ”‚ allâ”śÂˇ sus avanzadas para libra a la ciudad de la aproximaciâ”śâ”‚n de los invasores. Era entonces un convento de frailes capuchinos. Cuando los franceses se posesionaron de â”śÂ®l, replegâ”śĂ­ronse nuestras tropas hacia la puerta del Carmen." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64878500, -0.88904500, '0101000020E6100000A583F57F0E73ECBF53910A630BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582662528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582662528.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582662528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21292, 'Puerta del Carmen c.1908', 'Vista de la Puerta del Carmen y su paisanaje, desde su antiguo lado exterior o extramuros. Fuente visual: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27369997886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27369997886.webp', 'https://www.flickr.com/photos/zaragozaantigua/27369997886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21328, 'Puerta del Carmen c.1908', 'Imagen de la Puerta del Carmen en su tradicional entorno de la encrucijada entre el paseo de Marâ”śÂˇa Agustâ”śÂˇn (izquierda), el paseo de Pamplona (derecha), la calle de Hernâ”śĂ­n Cortâ”śÂ®s (hacia la izquierda) y la arbolada calle de la Soberanâ”śÂˇa Nacional (hacia el fondo). La puerta conserva todavâ”śÂˇa los â”śâ•‘ltimos postigos de madera de su paso central, asâ”śÂˇ como los cilindros de piedra que lo protegâ”śÂˇan del trâ”śĂ­nsito de vehâ”śÂˇculos rodados. Flanquean la puerta tenderetes festivos. Hemos volteado horizontalmente la imagen original para que el convento de la Encarnaciâ”śâ”‚n del fondo no pierda el norte.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64985900, -0.88765000, '0101000020E6100000BA6B09F9A067ECBF710168942ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50165660223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50165660223.webp', 'https://www.flickr.com/photos/zaragozaantigua/50165660223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21359, 'Puerta del Carmen 1900', 'Imagen capturada en el arranque del paseo de Marâ”śÂˇa Agustâ”śÂˇn y centrada en la Puerta del Carmen tras que que daba comienzo la arbolada calle de la Soberanâ”śÂˇa Nacional donde a la derecha, a continuaciâ”śâ”‚n de los edificios de la fotografâ”śÂˇa, quedaba el Depâ”śâ”‚sito de Cadâ”śĂ­veres de la ciudad.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785920358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785920358.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785920358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21510, 'Sommiers Andrâ”śÂ®s Lucâ”śÂˇa 1926', 'Antonio Beterâ”śÂ® Salvador naciâ”śâ”‚ en la ciudad en 1899, en familia pobre. Consiguiâ”śâ”‚ estudiar, y entrâ”śâ”‚ a trabajar con su tâ”śÂˇo Andrâ”śÂ®s Lucâ”śÂˇa Borge, propietario de un pequeâ”śâ–’o taller de reparaciâ”śâ”‚n de jergones, para llevar la contabilidad. Las cosas iban bien, a su tâ”śÂˇo le tocâ”śâ”‚ la loterâ”śÂˇa, y con el capital obtenido ampliaron las instalaciones fabriles de la calle Las Mercedes nâ”¬â•‘ 14. Ya en los aâ”śâ–’os 20, pasaron de la mera reparaciâ”śâ”‚n a la fabricaciâ”śâ”‚n de nuevos modelos, y crearon un jergâ”śâ”‚n sin muelles compuesto por una tela metâ”śĂ­lica insertada en un bastidor, que llamaron somier "Numancia". Fue el detonante de un crecimiento notable, que incluyâ”śâ”‚ el establecimiento de fâ”śĂ­bricas fuera de Zaragoza. Tras la guerra 1936-1939, Andrâ”śÂ®s Lucâ”śÂˇa dejâ”śâ”‚ la direcciâ”śâ”‚n de la fâ”śĂ­brica de Madrid a Antonio Beterâ”śÂ®, que en 1949 constituyâ”śâ”‚ la compaâ”śâ–’â”śÂˇa Fâ”śĂ­bricas Lucâ”śÂˇa Antonio Beterâ”śÂ®, S.A." (FLABESA). Una dâ”śÂ®cada mâ”śĂ­s tarde, fue redenominada "Flex". En la imagen, publicidad de la fâ”śĂ­brica de la calle Las Mercedes, luego calle Almagro. Fuente visual: "Aragâ”śâ”‚n : revista grâ”śĂ­fica de cultura aragonesa" (Aâ”śâ–’o II, Nâ”¬â•‘ 9, junio 1926). Fuente textual: www.mcnbiografias.com/app-bio/do/show?key=betere-salvador...', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64836800, -0.88795800, '0101000020E6100000161747E5266AECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15658340065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15658340065.webp', 'https://www.flickr.com/photos/zaragozaantigua/15658340065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21555, 'Puerta del Carmen 1927', 'Foto: A. de la Barrera. "Aislamiento de la Puerta del Carmen. Desfile de Artillerâ”śÂˇa". Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21381835558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21381835558.webp', 'https://www.flickr.com/photos/zaragozaantigua/21381835558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21600, 'Puerta del Carmen 1927', 'Institucional inauguraciâ”śâ”‚n del "aislamiento" de la puerta del Carmen, que supuso el derribo de aquellas viviendas que, a la derecha de la imagen, recordaban que, durante siglos, fue una puerta de verdad. En esas viviendas estuvo, desde 1895, el original Cafâ”śÂ® Levante, que hubo de emigrar a otro sitio. Esta puerta, como escenario de sucesos sin par en la historia de la ciudad, fue despojada de su funcionalidad, y convertida en exento monumento, cada vez mâ”śĂ­s exento y descontextualizado de su entorno. En la imagen, el alcalde Miguel Alluâ”śÂ® Salvador en pleno "meeting". Tras â”śÂ®l, el resto de la corporaciâ”śâ”‚n municipal. Al fondo, el convento de la Encarnaciâ”śâ”‚n. Fuente visual: Foto: Alejandro de la Barrera www.todocoleccion.net/', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25803894956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25803894956.webp', 'https://www.flickr.com/photos/zaragozaantigua/25803894956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21601, 'P.â”¬â•‘ de Pamplona 1927', 'Imagen panorâ”śĂ­mica del entronque del paseo de Pamplona con la puerta del Carmen, capturada en altura por Alejandro de la Barrera durante el Institucional acto de inauguraciâ”śâ”‚n del "aislamiento" de la puerta del Carmen, en 1927, que en la imagen queda a la izquierda, fuera de plano. Nutrida presencia de autoridades, invitados, y pâ”śâ•‘blico en general, congregados al final del frondoso bulevar del paseo de Pamplona. Al fondo, taller y garaje de â”śĂĽgreda Automâ”śâ”‚vil en una replaceta que luego desapareciâ”śâ”‚ con la prolongaciâ”śâ”‚n de la calle de Canfranc, calle que entonces acababa en la achaflanada esquina del nuevo colegio de la "Enseâ”śâ–’anza", cuyos andamiajes de obras aparecen en franca progresiâ”śâ”‚n. Al fondo, los restos del antiguo convento de Santa Teresa de las Carmelitas Descalzas de San Josâ”śÂ®, acondicionado como Gobierno Militar. Un retratista se afana en retratar a las fuerzas vivas militares, religiosas, e institucionales, encabezadas por el hiperactivo alcalde, y nunca bien ponderado, Miguel Alluâ”śÂ®. Fuente visual: Foto: Alejandro de la Barrera www.todocoleccion.net/', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64955700, -0.88745500, '0101000020E6100000677E35070866ECBFA6F10BAF24D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25804414256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25804414256.webp', 'https://www.flickr.com/photos/zaragozaantigua/25804414256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21662, 'Puerta del Carmen 1927', 'Fotograma de un reportaje dedicado a la inauguraciâ”śâ”‚n oficial, el dâ”śÂˇa 18 de mayo de ese aâ”śâ–’o, del "total aislamiento" de la Puerta del Carmen que finalmente convirtiâ”śâ”‚ a esta reliquia en un monumento exento respecto a las edificaciones del entorno. Una multitud de paisanos abarrotaron la confluencia entre la calle de la Soberanâ”śÂˇa Nacional (en la imagen, tras la puerta), la avenida de Hernâ”śĂ­n Cortâ”śÂ®s y los paseos de Pamplona y de Marâ”śÂˇa Agustâ”śÂˇn, mientras tenâ”śÂˇa lugar una "fiesta patriâ”śâ”‚tica" de carâ”śĂ­cter militar y religioso con numerosos representantes locales de las instituciones del râ”śÂ®gimen dictatorial del general Primo de Rivera. El inefable alcalde Miguel Alluâ”śÂ® Salvador protagonizâ”śâ”‚ un mitin en el que denominâ”śâ”‚ de forma pionera "altar de la patria" a esta puerta y "santuario de patriotismo" a Zaragoza, câ”śâ”‚digos que volverâ”śÂˇan a ser utilizados hasta la saciedad una dâ”śÂ®cada despuâ”śÂ®s, en el marco de otra dictadura.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54722175090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54722175090.webp', 'https://www.flickr.com/photos/zaragozaantigua/54722175090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21903, 'Puerta del Carmen 1931', 'Imagen centrada en la Puerta del Carmen y su aspecto tras las obras de aislamiento que desde 1927 la dejaron aislada de su entorno edilicio. A la izquierda, tapias de la huerta de la iglesia y convento de la Encarnaciâ”śâ”‚n de las carmelitas descalzas y la arbolada calle de la Soberanâ”śÂˇa Nacional, cuyo tramo final del lado de los impares queda tras la puerta, en cuya esquina con el paseo de Pamplona destaca el Cafâ”śÂ® Aragâ”śâ”‚n, muy cerca de donde estuvo el Cafâ”śÂ® de Levante hasta 1926. A la derecha, irregular esquina del paseo donde destaca el taller y garaje de la empresa de autobuses â”śĂĽgreda Automâ”śâ”‚vil.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51617755764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51617755764.webp', 'https://www.flickr.com/photos/zaragozaantigua/51617755764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21909, 'Puerta del Carmen c.1934', 'Imagen capturada en el â”śâ•‘ltimo tramo de la calle de la Soberanâ”śÂˇa Nacional, a la altura del convento de la Encarnaciâ”śâ”‚n (a la derecha, fuera de plano) y centrada en la Puerta del Carmen, con su aspecto tras las obras de aislamiento realizadas la dâ”śÂ®cada anterior. Tras ella y hacia el fondo se abre la avenida de Hernâ”śĂ­n Cortâ”śÂ®s. Un carro se encamina hacia el paseo de Pamplona mediante una llamativa maniobra si se mira desde un punto de vista actual. Entonces, no. El fotâ”śâ”‚grafo titulâ”śâ”‚ esta fotografâ”śÂˇa de forma muy apropiada "Only gate left to city" (la â”śâ•‘nica puerta que queda en la ciudad).', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65010800, -0.88731700, '0101000020E610000025EA059FE664ECBF1A6F2BBD36D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51760200560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51760200560.webp', 'https://www.flickr.com/photos/zaragozaantigua/51760200560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21977, 'Puerta del Carmen 1944', 'Celebraciones militares fascistas del Dâ”śÂˇa de los Caâ”śÂˇdos, el 30 de octubre de 1944, ante la Puerta del Carmen. Al fondo, el Convento de las Carmelitas de la Encarnaciâ”śâ”‚n, en la esquina del paseo de Marâ”śÂˇa Agustâ”śÂˇn con la calle del General Sanjurjo (hoy avenida de Câ”śÂ®sar Augusto). Fuente: www.keecua.com/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24929016893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24929016893.webp', 'https://www.flickr.com/photos/zaragozaantigua/24929016893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22163, 'Puerta del Carmen 1954', 'Con motivo del Congreso Mariano Nacional celebrado en Zaragoza en octubre de 1954, se congregaron imâ”śĂ­genes de la Virgen procedentes de todo el paâ”śÂˇs. En la imagen, la Virgen de la Peana de Borja, ante la Puerta del Carmen, convenientemente decorada. Detrâ”śĂ­s, fuera de nuestra vista, la ciudad consolidada duerme la plomiza paz religiosa supuesta e impuesta. Fuente: cesbor.blogspot.com.es/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64988000, -0.88767300, '0101000020E6100000C5591135D167ECBF892991442FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30814265013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30814265013.webp', 'https://www.flickr.com/photos/zaragozaantigua/30814265013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22231, 'Puerta del Carmen c.1954', 'Imagen centrada en la Puerta del Carmen rodeada de la barandilla metâ”śĂ­lica con que fue aislada en 1927. Al fondo, muro perimetral de la huerta del convento de la Encarnaciâ”śâ”‚n, cuya iglesia se destaca entre el gran vano central de la puerta, y cuya fachada principal se abre por la calle del General Sanjurjo.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64993900, -0.88768200, '0101000020E610000091EEE714E467ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49942622867.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49942622867.webp', 'https://www.flickr.com/photos/zaragozaantigua/49942622867/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22304, 'Puerta del Carmen 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Puerta del Carmen". Se han dejado la puerta abierta, y podemos ver el aspecto de la calle del General Sanjurjo (antigua de la Soberanâ”śÂˇa Nacional), antes del "lifting" que la convertirâ”śÂˇa en Vâ”śÂˇa Imperial primero, Câ”śÂ®sar Augusto despuâ”śÂ®s. Con la cirugâ”śÂˇa, se recortaron tambiâ”śÂ®n los edificios de la derecha, aunque los que les sustituyeron compensaron con creces esa "pâ”śÂ®rdida", creciendo en vertical como regados por concentrado de vitaminas. Cayeron tambiâ”śÂ®n los â”śĂ­rboles, y sembraron sal para que luego no creciese nada verde (orgâ”śĂ­nico). A la izquierda, tras los caâ”śâ–’izos de obra, la construcciâ”śâ”‚n del nuevo Monasterio de la Encarnaciâ”śâ”‚n (Madres Carmelitas). Fuente visual: fototeca.us.es/imagen.jsp?id=25836&tipo=v&elto=1&...', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64983000, -0.88759400, '0101000020E6100000C00644882B67ECBFD7FA22A12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15617866936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15617866936.webp', 'https://www.flickr.com/photos/zaragozaantigua/15617866936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22325, 'Calle de Hernâ”śĂ­n Cortâ”śÂ®s 1962', 'Un reportaje fotogrâ”śĂ­fico familiar, segâ”śâ•‘n dâ”śâ”‚nde haya sido realizado, es algo mâ”śĂ­s que un reportaje fotogrâ”śĂ­fico familiar. Tal es el caso. La nena ha sido retratada en la todavâ”śÂˇa bastante tranquila, a efectos de circulaciâ”śâ”‚n rodada a motor de explosiâ”śâ”‚n, calle de Hernâ”śĂ­n Cortâ”śÂ®s, que fuera en tiempos tranquilo camino al convento de los Capuchinos que, una vez desamortizado, fue militarizado. Aâ”śâ–’os despuâ”śÂ®s de esta imagen, la calle se convirtiâ”śâ”‚ en prolongaciâ”śâ”‚n de la autopista de Câ”śÂ®sar Augusto, y los niâ”śâ–’os dejaron de corretear, y los â”śĂ­rboles, fuera. En la imagen, al fondo a la derecha, vista parcial del espectacular colegio de las "Adoratrices Esclavas del Santâ”śÂˇsimo y de la Caridad", en esa ubicaciâ”śâ”‚n desde 1910, en el nâ”¬â•‘ 10 de la calle. En 1972, durante la no oficial "Operaciâ”śâ”‚n conventos y colegios religiosos", las Adoratrices se mudaron a otros pagos de la periferia, el edificio fue vendido, pagado, y piqueteado, y una enorme urbanizaciâ”śâ”‚n con bloques de nueve alturas surgiâ”śâ”‚ en el solar resultante. La nena, bien maja.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64917000, -0.88887300, '0101000020E61000005E8429CAA571ECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16371316546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16371316546.webp', 'https://www.flickr.com/photos/zaragozaantigua/16371316546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22499, 'Calle del General Sanjurjo c.1964', 'Imagen centrada en la fachada principal del convento de la Encarnaciâ”śâ”‚n de las carmelitas recayente a la calle del General Sanjurjo, al norte de la Puerta del Carmen. Este edificio fue diseâ”śâ–’ado en formas eclâ”śÂ®cticas por Elâ”śÂˇas Ballespâ”śÂˇn Larroyed a finales del siglo XIX, cuando esta era la calle de la Soberanâ”śÂˇa Nacional, como dependencias anexas a la dieciochesca iglesia conventual de esta orden. Poco despuâ”śÂ®s de la captura de esta fotografâ”śÂˇa, este edificio serâ”śÂˇa derribado para dar paso a un nuevo complejo carmelita construido sobre la antigua zona de huerta chaflanera con el paseo de Marâ”śÂˇa Agustâ”śÂˇn y la nueva Vâ”śÂˇa Imperial.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65045200, -0.88713500, '0101000020E6100000FA6184F06863ECBF14CFD90242D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49603730673.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49603730673.webp', 'https://www.flickr.com/photos/zaragozaantigua/49603730673/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22914, 'P.â”¬â•‘ de Mâ”¬Â¬ Agustâ”śÂˇn 1985', 'Movilizaciâ”śâ”‚n contra Reagan y la OTAN convocada por la Asamblea Ciudadana el 5 de mayo de ese aâ”śâ–’o ante la visita a Espaâ”śâ–’a del presidente de Estados Unidos para garantizar el futuro de sus bases militares, y pedir colaboraciâ”śâ”‚n en su cruzada contra la Nicaragua sandinista. La vista, que ha sido capturada desde la altura del nâ”¬â•‘ 16 del paseo de Pamplona, muestra a los participantes formando la consigna OTAN no y el sâ”śÂˇmbolo de la paz en el tramo del paseo de Marâ”śÂˇa Agustâ”śÂˇn hasta el Colegio Pâ”śâ•‘blico Joaquâ”śÂˇn Costa. Fuente: Agencia EFE.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65020900, -0.88824200, '0101000020E610000050E09D7C7A6CECBF4D486B0C3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24599112706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24599112706.webp', 'https://www.flickr.com/photos/zaragozaantigua/24599112706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22957, 'Puerta del Carmen 1983', 'Imagen capturada desde el punto de vista de un peatâ”śâ”‚n situado temerariamente al principio de la calle de Hernâ”śĂ­n Cortâ”śÂ®s, y centrada en la "histâ”śâ”‚rica" (sic) Puerta del Carmen con el fondo de la avenida de Câ”śÂ®sar Augusto. Esta era la dieciochesca versiâ”śâ”‚n de la histâ”śâ”‚rica puerta que desde antiguo aquâ”śÂˇ abrâ”śÂˇa/cerraba el ingreso a la ciudad por el camino de Madrid que pasaba por Daroca. A la izquierda, el moderno convento de la Encarnaciâ”śâ”‚n, en un entorno descontextualizado desde la dâ”śÂ®cada de los aâ”śâ–’os 60 del pasado siglo XX, especialmente desde la construcciâ”śâ”‚n del rascacielos de la derecha, que marcâ”śâ”‚ tendencia a los nuevos inmuebles construidos desde entonces en la Vâ”śÂˇa Imperial. Tras â”śÂ®l, solar esquinero con la calle de Josâ”śÂ® Luis Albareda que serâ”śÂˇa construido pocos aâ”śâ–’os despuâ”śÂ®s de esta fotografâ”śÂˇa. Al fondo, visible a travâ”śÂ®s del vano central de la puerta, el "Edificio Residencial-Comercial Salamero", sito junto a la homâ”śâ”‚nima plaza, antigua de la Santa Fe.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64985900, -0.88762800, '0101000020E6100000C571E0D57267ECBF710168942ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49340625047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49340625047.webp', 'https://www.flickr.com/photos/zaragozaantigua/49340625047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22981, 'Puerta del Carmen 1997', 'Rehabilitaciâ”śâ”‚n de la Puerta del Carmen de Zaragoza, tras el golpe recibido al chocar un autobâ”śâ•‘s contra ella. La toma, nocturna, evoca monstruos, oscurantismo, torturas rituales. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15913810051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15913810051.webp', 'https://www.flickr.com/photos/zaragozaantigua/15913810051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22988, 'Puerta del Carmen 1997', 'Imagen del estado de la Puerta del Carmen de Zaragoza tras sufrir el choque de un autocar, el 23 de febrero de 1997. Se observa, ademâ”śĂ­s de la caâ”śÂˇda de la bola de piedra, el desplazamiento del lateral. Fuente: Foto â”śĂĽngel de Castro, en www.elperiodicodearagon.com/', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19860137941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19860137941.webp', 'https://www.flickr.com/photos/zaragozaantigua/19860137941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23014, 'Puerta del Carmen 1997', 'Imagen de la puerta del Carmen embalada y tapiada durante el proceso de reparaciâ”śâ”‚n a la que se vio sometida tras ser impactada por un autobâ”śâ•‘s urbano. La isleta donde estâ”śĂ­ enclavada fue, ademâ”śĂ­s, reforzada con pivotes en las zonas laterales, las mâ”śĂ­s expuestas a potenciales nuevos impactos directos del trâ”śĂ­fico rodado que la asedia. Al fondo, la avenida de Câ”śÂ®sar Augusto. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental", SIPA.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64985600, -0.88767300, '0101000020E6100000C5591135D167ECBF008E3D7B2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34911631795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34911631795.webp', 'https://www.flickr.com/photos/zaragozaantigua/34911631795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23273, 'Baterâ”śÂˇa de la Puerta del Carmen 1808', '"Baterâ”śÂˇa de la Puerta del Carmen". Serie Ruinas de Zaragoza, de Juan Gâ”śĂ­lvez (dibujo) y Fernando Brambila (grabado), Câ”śĂ­diz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65019300, -0.88779100, '0101000020E610000040DCD5ABC868ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18931581573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18931581573.webp', 'https://www.flickr.com/photos/zaragozaantigua/18931581573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23968, 'P.â”¬â•‘ de Pamplona 1974', 'Archivo Municipal Zaragoza. Josâ”śÂ® Jaria Serrano. 23/05/1974. "Carroza de las majas de Alemania y Yugoslavia." Desfile con motivo de las "Fiestas de Primavera-Coso Blanco". La carroza es un jeep de los EEUU de norteamâ”śÂ®rica. La maja alemana es de la Repâ”śâ•‘blica Federal de Alemania, y la maja yugoslava, de la Repâ”śâ•‘blica Federal Socialista de Yugoslavia. El conductor, indâ”śÂˇgena del Reino de Espaâ”śâ–’a. La caravana transcurre por el Pâ”¬â•‘ de Pamplona. Al fondo, tras la peineta gigante, uno de los gigantes levantados al albur del ensanchamiento de Câ”śÂ®sar Augusto. A su derecha, el edificio Canfranc-Pâ”¬â•‘ Pamplona, supervive. Su vecino a la derecha, no.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64912200, -0.88721000, '0101000020E6100000A4E4D5390664ECBF9B8E006E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093537330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093537330.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093537330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24003, 'P.â”¬â•‘ de Pamplona 1974', '"Carroza de las majas de Finlandia y Paraguay." Celebraciâ”śâ”‚n en mayo con motivo de las "Fiestas de Primavera-Coso Blanco". La carroza es un jeep que transita por el paseo de Pamplona, y esta imagen permite una amplia visual, al fondo, y a la derecha, del antiguo edificio del paseo con los nâ”śâ•‘meros 12-14, que unos pocos aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇa derribado y sustituido por lo que ahora hay. Fuente visual: Josâ”śÂ® Jaria Serrano (Archivo Pâ”śâ•‘blico Municipal)', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64922800, -0.88710100, '0101000020E6100000F5F6E7A22163ECBFE1D231E719D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22479738907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22479738907.webp', 'https://www.flickr.com/photos/zaragozaantigua/22479738907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24104, 'Pâ”¬â•‘. de Pamplona 1972', 'Imagen capturada en el paseo de Pamplona durante las Fiestas de Primavera y dentro del evento denominado "Concurso de la Maja Internacional", donde veinticinco "bellas seâ”śâ–’oritas" representantes de sus respectivos paâ”śÂˇses se disputaron ese tâ”śÂˇtulo en Zaragoza. La luminosa y colorista fotografâ”śÂˇa fue realizada durante el "Coso Blanco" celebrado en este paseo, consistente en un desfile de "carrozas" o "jeeps con peineta", donde las pretendientes al galardâ”śâ”‚n y por parejas, ataviadas con sus respectivos trajes folklâ”śâ”‚ricos tâ”śÂˇpicos, lanzaban serpentinas y confetti a los miles de asistentes que observaban su paso. En primer tâ”śÂ®rmino, la "carroza" con la representante de USA y su "traje regional" que, a falta de otras referencias histâ”śâ”‚ricas, parece consistir en un remedo femenino del traje del simbâ”śâ”‚lico "Tâ”śÂˇo Sam"; a su lado, menos espectacular, la representante de la monarquâ”śÂˇa federal parlamentaria de Bâ”śÂ®lgica. Al fondo y a la izquierda, una vista del grupo de "Majorettes" de Zaragoza que amenizaban el desfile ademâ”śĂ­s de bandas de mâ”śâ•‘sica y fanfarrias, y lanzamiento de cohetes. Tras ellas, el nuevo convento de las Encarnaciâ”śâ”‚n, y el moderno entorno de la Puerta del Carmen donde destaca el enorme Edificio Ebrosa y el rascacielos que seâ”śâ–’ala el arranque de la calle del General Sanjurjo, un tramo de la cual tambiâ”śÂ®n fue escenario del paso de este "Coso Blanco" coincidiendo con la celebraciâ”śâ”‚n del solemne dâ”śÂˇa de la Ascensiâ”śâ”‚n, uno de esos tres dâ”śÂˇas que la tradiciâ”śâ”‚n cristiana dice que "brillan mâ”śĂ­s que el sol".', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64920200, -0.88723100, '0101000020E610000081EA1F443264ECBFB83F170D19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51505927636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51505927636.webp', 'https://www.flickr.com/photos/zaragozaantigua/51505927636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24526, 'P.â”¬â•‘ de Pamplona 1982', 'Imagen centrada en la fachada del antiguo nâ”¬â•‘ 7 del paseo de Pamplona, diseâ”śâ–’ado por el arquitecto Julio Bravo en 1901 para Ramâ”śâ”‚n Hernâ”śĂ­ndez donde se ingresaba a los antiguos lavaderos de Pignatelli desde el paseo de la Lealtad. De tres plantas mâ”śĂ­s los bajos, esta casa era una muestra de las eclâ”śÂ®cticas formas usadas en el trâ”śĂ­nsito del siglo XIX al XX. En el momento de capturar la imagen, los bajos comerciales estaban ocupados por una tienda de muebles de Simâ”śâ”‚n Loscertales Bona, que serâ”śÂˇa la â”śâ•‘ltima en activo en la ciudad. A principios del siglo XXI este edificio fue objeto de una intensa remodelaciâ”śâ”‚n que le aâ”śâ–’adiâ”śâ”‚ cuatro plantas en altura de traza postmoderna. A la izquierda, el antiguo nâ”¬â•‘ 5 del paseo, que originalmente tambiâ”śÂ®n fue diseâ”śâ–’ado por Julio Bravo, y que tambiâ”śÂ®n fue objeto de una profunda transformaciâ”śâ”‚n tanto en altura como en formas. A la derecha, el modernâ”śÂˇsimo y reciente nâ”¬â•‘ 9, de diez alturas. Fuente visual: AMZ', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64845800, -0.88694000, '0101000020E6100000A774B0FECF61ECBF2F6AF7AB00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42261475914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42261475914.webp', 'https://www.flickr.com/photos/zaragozaantigua/42261475914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24962, 'Velocipedistas Zaragoza 1882', 'Revista "Aragâ”śâ”‚n", SIPA, nâ”¬â•‘ 25, octubre 1927. 1882. Los anales se remontan a los aâ”śâ–’os 70 (del XIX) para atestiguar la epifanâ”śÂˇa del ciclismo zaragozano. El lugar: Teatro "Prado Aragonâ”śÂ®s", donde San Miguel con Isaac Peral. Jâ”śâ”‚venes de la "buena" sociedad de entonces maniobraban en velocâ”śÂˇpedos de madera herederos de la "draisiana" o "mâ”śĂ­quina andante" de comienzos del siglo. Un poco despuâ”śÂ®s la tâ”śÂ®cnica introdujo el metal y los pedales, y una rueda delantera que alcanzaba el metro y medio de altura (la trasera sâ”śâ”‚lo llegaba a los 40 ctm.) Estos nuevos artefactos, y los locos montados en ellos, pronto causaron sensaciâ”śâ”‚n (positiva) con su rodaje por las calles de la ciudad, conquistando prosâ”śÂ®litos y militantes hasta el punto que, un poco mâ”śĂ­s tarde, aâ”śâ–’o de 1882, se constituyâ”śâ”‚ la primera entidad ciclista local, denominada "Sociedad de Velocipedistas", con domicilio social en el Paseo de Pamplona. La imagen capta un posado de algunos de esos pioneros de las dos ruedas, sin vâ”śÂ®rtigo, junto con sus locos cacharros, a la puerta de su sede social: Gamborenea, Marco, Baraza, Boayed, Cibri, Lostz, y Sra.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.64937800, -0.88734400, '0101000020E61000008BA8893E1F65ECBFF65E7CD11ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850347741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850347741.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850347741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24967, 'Epi 1974', 'Juan Antonio San Epifanio naciâ”śâ”‚ en la calle Damiâ”śĂ­n Forment en 1959. En 1968 su familia se mudâ”śâ”‚ a la calle Josâ”śÂ® Pellicer (Barrio de San Josâ”śÂ®), donde viviâ”śâ”‚ hasta los 15 aâ”śâ–’os. Comenzâ”śâ”‚ la prâ”śĂ­ctica del baloncesto en la Instituciâ”śâ”‚n Sindical Virgen del Pilar (Paseo Reyes de Aragâ”śâ”‚n), junto al Canal Imperial y enfrente del Stadium Casablanca. Aunque "era muy malo" (segâ”śâ•‘n â”śÂ®l mismo), era muy alto, y eso en baloncesto es un valor seguro. Lo de ser alto le servâ”śÂˇa, ademâ”śĂ­s, para saltar mejor la valla del cercano colegio de los PP. Agustinos, donde practicaba con las canastas del patio. En 1971 entrâ”śâ”‚ en el C. N. Helios, hasta llegar a la categorâ”śÂˇa juvenil. Con quince aâ”śâ–’os de edad, fue fichado por el F.C. Barcelona por mediaciâ”śâ”‚n de su hermano mayor. Allâ”śÂˇ estarâ”śÂˇa hasta 1995, firmando una trayectoria deportiva mâ”śĂ­s que impresionante. En la imagen, Juan Antonio San Epifanio, "Epi", cuando era juvenil en el Helios, posando ante la Puerta del Carmen.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64977300, -0.88758800, '0101000020E6100000384E0AF31E67ECBF7369FCC22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15256350857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15256350857.webp', 'https://www.flickr.com/photos/zaragozaantigua/15256350857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25072, 'Alfonso XIII, 1908', '"Francia y Espaâ”śâ–’a. Monsieur Cruppi, ministro de Comercio, y Revoil, embajador de Francia, saludan a Su Majestad Alfonso XIII en Zaragoza". Ilustraciâ”śâ”‚n, 1908. Los personajes estâ”śĂ­n situados extramuros de la ciudad, con la Puerta del Carmen a sus espaldas. Fuente: Le Petit Journal, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64961200, -0.88779200, '0101000020E610000057D0B4C4CA68ECBF698B6B7C26D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18342645394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18342645394.webp', 'https://www.flickr.com/photos/zaragozaantigua/18342645394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25463, 'Puerta del Carmen 1883', 'A.M.Z. Sign. 0884. Puerta del Carmen bombardeada por los franceses en los dos câ”śÂ®lebres sitios de 1808 y 1809 (de fotografâ”śÂˇa de Laurent). 1883. La puerta de Baltax o del Carmen (1782) cerraba la ciudad al suroeste. Actualmente se conserva en pie, al final de la avenida Câ”śÂ®sar Augusto.', 1883, 1883, 1883, 'Siglo XIX', 'CENTRO', 41.64984000, -0.88762200, '0101000020E61000003DB9A6406667ECBFFAD005F52DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14835922566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14835922566.webp', 'https://www.flickr.com/photos/zaragozaantigua/14835922566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25464, 'Puerta del Carmen 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”śÂˇa. 1872-1879. "Puerta de Nuestra Sra. del Carmen, memorable por la defensa que hizo de ella la heroâ”śÂˇna de Zaragoza durante el famoso sitio de 1808."', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64986700, -0.88754800, '0101000020E6100000AA2A3410CB66ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14865951902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14865951902.webp', 'https://www.flickr.com/photos/zaragozaantigua/14865951902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
