INSERT INTO public.photos VALUES (25466, 'Puerta del Carmen 1951', 'Archivo Municipal de Zaragoza. Archivo Arribas. 1950. "[Puerta del Carmen y Paseo Marâ”śÂˇa Agustâ”śÂˇn]". "La Puerta del Carmen estâ”śĂ­ situada en la confluencia del Paseo de Pamplona con el inicio de la Vâ”śÂˇa Imperial, se denominâ”śâ”‚ Puerta de Baltax antes de llamarle del Carmen. A los pocos aâ”śâ–’os de construirse padeciâ”śâ”‚ los efectos destructores de los Sitios, posteriormente en 1838, durante la primera Guerra Carlista, el ejâ”śÂ®rcito de Cabaâ”śâ–’ero asaltâ”śâ”‚ por dicha entrada la ciudad. Se trata de una sencilla puerta de piedra, cuya estructura a modo de arco triunfal romano evoca conocidos ejemplos neoclâ”śĂ­sicos madrileâ”śâ–’os. Compuesta de un cuerpo central mâ”śĂ­s alto y dos cuerpos laterales, cada uno de ellos presenta un vano rectangular. El central sirviâ”śâ”‚ para el trâ”śĂ­nsito de animales y vehâ”śÂˇculos y los laterales sâ”śâ”‚lo para viandantes. Su ornamentaciâ”śâ”‚n es escasa, se reduce a la piedra clasicista y a su remate con decoraciâ”śâ”‚n de bolas."', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15044018576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15044018576.webp', 'https://www.flickr.com/photos/zaragozaantigua/15044018576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25469, 'Puerta del Carmen 1889', '"Saragosse. Porte del Carmen". J. Lâ”śÂ®vy et Cie, 1889. Agence Roger-Viollet, Parâ”śÂˇs. Fuente: Zaragoza en la mirada ajena. Cortes de Aragâ”śâ”‚n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16806009622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16806009622.webp', 'https://www.flickr.com/photos/zaragozaantigua/16806009622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25470, 'P.â”¬â•‘ de Pamplona 1962', 'Imagen de la "trasformaciâ”śâ”‚n de la estructura" del antiguo paseo de Pamplona, que en plata significaba convertirlo en lo que el paseo de la Independencia era ya desde el aâ”śâ–’o anterior: una despejada pista para el trâ”śĂ­nsito del trâ”śĂ­fico rodado a motor de explosiâ”śâ”‚n. Esta actuaciâ”śâ”‚n era calificada de "mejora", y suponâ”śÂˇa eliminar los males del andâ”śÂ®n central peatonal, y todo lo que en â”śÂ®l hubiera, o hubiese. Unos aâ”śâ–’os antes ya habâ”śÂˇa sido desmontado el "Monumento a la Exposiciâ”śâ”‚n Hispano-Francesa de 1908", y trasladado donde no molestara. En la imagen, estado de la cuestiâ”śâ”‚n con remociâ”śâ”‚n de â”śĂ­rboles entre bancos de sentarse y montoneras de tierra. Al fondo, la puerta del Carmen, y mâ”śĂ­s al fondo, a la derecha, aprovechando lo despejado del entorno, despunta la torrecilla oriental de la Casa-Noviciado de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”śâ•‘blico Municipal.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22516579533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22516579533.webp', 'https://www.flickr.com/photos/zaragozaantigua/22516579533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25471, 'Puerta del Carmen 1955', 'Nocturna imagen de la Puerta del Carmen iluminada, todavâ”śÂˇa con su perâ”śÂˇmetro cercado y ajardinado, cuando aâ”śâ•‘n no era una rotonda para automâ”śâ”‚viles. Al fondo, la calle General Sanjurjo, con mâ”śĂ­s oscuros, que claros. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22575360344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22575360344.webp', 'https://www.flickr.com/photos/zaragozaantigua/22575360344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
